    s1 = lb.ref("s1", "( ∃ x φ ↔ ∃ y ψ )", h1, ref="cbvexvw", note="cbvexvw")
    s2 = lb.ref("s2", "( E* x φ ↔ E* y ψ )", h1, ref="cbvmovw", note="cbvmovw")
    s3 = lb.ref("s3", "( ( ∃ x φ ∧ E* x φ ) ↔ ( ∃ y ψ ∧ E* y ψ ) )", s1, s2, ref="anbi12i", note="anbi12i")
    s4 = lb.ref("s4", "( E! x φ ↔ ( ∃ x φ ∧ E* x φ ) )", ref="df-eu", note="df-eu")
    s5 = lb.ref("s5", "( E! y ψ ↔ ( ∃ y ψ ∧ E* y ψ ) )", ref="df-eu", note="df-eu")
    res = lb.ref("res", "( E! x φ ↔ E! y ψ )", s3, s4, s5, ref="3bitr4i", note="3bitr4i")
    return lb.build(res)

