    s4 = lb.ref("s4", "( ( ∃ x ∃ y φ ∧ ∀ x ( ∃ y φ → E! y φ ) ) → ( E! x E! y φ → E! x ∃ y φ ) )", ref="euim", note="euim")
    s5 = lb.ref("s5", "( ( ∃ x ∃ y φ ∧ ∀ x E* y φ ) → ( E! x E! y φ → E! x ∃ y φ ) )", s3, s4, ref="sylan2b", note="sylan2b")
    s6 = lb.ref("s6", "( ∃ x ∃ y φ → ( ∀ x E* y φ → ( E! x E! y φ → E! x ∃ y φ ) ) )", s5, ref="ex", note="ex")
    s7 = lb.ref("s7", "( E! x E! y φ → ( ∀ x E* y φ → ( E! x E! y φ → E! x ∃ y φ ) ) )", s1, s6, ref="syl", note="syl")
    s8 = lb.ref("s8", "( ∀ x E* y φ → ( E! x E! y φ → E! x ∃ y φ ) )", s7, ref="pm2.43b", note="pm2.43b")
